import{_ as e,c as a,o as i,a as l}from"./app.6f6e89c1.js";const _=JSON.parse('{"title":"前端技术架构与工程","description":"","frontmatter":{},"headers":[{"level":2,"title":"业务逻辑与交互逻辑","slug":"业务逻辑与交互逻辑","link":"#业务逻辑与交互逻辑","children":[]},{"level":2,"title":"前端的边界","slug":"前端的边界","link":"#前端的边界","children":[]},{"level":2,"title":"前端与测试","slug":"前端与测试","link":"#前端与测试","children":[]},{"level":2,"title":"技术架构","slug":"技术架构","link":"#技术架构","children":[{"level":3,"title":"编程语言","slug":"编程语言","link":"#编程语言","children":[]},{"level":3,"title":"技术规范","slug":"技术规范","link":"#技术规范","children":[]},{"level":3,"title":"组件化","slug":"组件化","link":"#组件化","children":[]},{"level":3,"title":"前后端分离","slug":"前后端分离","link":"#前后端分离","children":[]},{"level":3,"title":"性能","slug":"性能","link":"#性能","children":[]}]},{"level":2,"title":"工程服务体系","slug":"工程服务体系","link":"#工程服务体系","children":[{"level":3,"title":"开发","slug":"开发","link":"#开发","children":[]},{"level":3,"title":"构建","slug":"构建","link":"#构建","children":[]},{"level":3,"title":"部署","slug":"部署","link":"#部署","children":[]},{"level":3,"title":"持续化","slug":"持续化","link":"#持续化","children":[]},{"level":3,"title":"监控和统计","slug":"监控和统计","link":"#监控和统计","children":[]}]}],"relativePath":"accumulation/front-end-architecture.md","lastUpdated":1671588986000}'),r={name:"accumulation/front-end-architecture.md"},h=l('<h1 id="前端技术架构与工程" tabindex="-1">前端技术架构与工程 <a class="header-anchor" href="#前端技术架构与工程" aria-hidden="true">#</a></h1><h2 id="业务逻辑与交互逻辑" tabindex="-1">业务逻辑与交互逻辑 <a class="header-anchor" href="#业务逻辑与交互逻辑" aria-hidden="true">#</a></h2><ul><li>表现层（Interface Layer）</li><li>表现控制层（Interface Control Layer）</li><li>业务逻辑层（Business Logic Layer）</li><li>数据访问层（Data Access Layer）</li><li>数据储存层（Data Storage Layer）</li></ul><p>分层架构是实现关注点分离的必要途径</p><blockquote><p>业务逻辑是现实业务规则的编码实现，决定了数据被创建、储存和修改的规则。 交互逻辑指的是将数据展示给用户的方式。</p></blockquote><h2 id="前端的边界" tabindex="-1">前端的边界 <a class="header-anchor" href="#前端的边界" aria-hidden="true">#</a></h2><p>分层架构最典型的优势之一是负责各层级的开发者可以实现并行开发。当前，前端仍然是围绕交互逻辑展开的。</p><h1 id="架构与工程" tabindex="-1">架构与工程 <a class="header-anchor" href="#架构与工程" aria-hidden="true">#</a></h1><p>代码和流程是软件工程的核心关注点。</p><p>从代码的角度考虑，工程的目标是保证软件的高可用性、可扩展性、可伸缩性、性能以及安全，这些要素共同组成了软件的技术架构。</p><p>架构之外，工程从更宏观的角度完善开发和维护流程的管控，强调项目迭代的规范性、有序性、可控性和高效性，并根据架构特征提供额外的辅助功能。</p><p>架构是工程的子集。</p><p>暂将前端工程化于架构之外的部分称为<strong>前端工程服务体系</strong>。</p><p>前端工程化 = 前端技术架构 + 前端工程服务体系</p><h1 id="零散的前端架构" tabindex="-1">零散的前端架构 <a class="header-anchor" href="#零散的前端架构" aria-hidden="true">#</a></h1><p>前端架构包括的环节：</p><ul><li>源码组织规范</li><li>组件化/模块化</li><li>数据管理</li><li>性能优化</li><li>前后端分离</li></ul><h1 id="模糊的前端工程边界" tabindex="-1">模糊的前端工程边界 <a class="header-anchor" href="#模糊的前端工程边界" aria-hidden="true">#</a></h1><h2 id="前端与测试" tabindex="-1">前端与测试 <a class="header-anchor" href="#前端与测试" aria-hidden="true">#</a></h2><p>单元测试、集成测试、端到端测试、验收测试。单元测试和集成测试通常由开发人员在将应用程序交付测试之前进行。端到端测试通常由测试工程师完成，测试范畴包括功能、性能、健壮性、稳定性等。验收测试指站在用户的角度去评估应用程序是否满足了需求，由需求方（通常为产品经理）负责。</p><h1 id="前端架构师的职责" tabindex="-1">前端架构师的职责 <a class="header-anchor" href="#前端架构师的职责" aria-hidden="true">#</a></h1><ul><li>根据业务特征设计合理的前端技术架构</li><li>根据架构特征搭建高效的前端工程服务体系</li></ul><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-hidden="true">#</a></h2><p>熵增（正熵）代表系统趋向无序，熵减（负熵）代表系统趋向有序。软件架构中，熵增的极端结果是<strong>彻底的重构</strong>。架构师的职责是通过及时、有效的干预，令软件架构产生负熵，以保持系统的有序。</p><p>软件架构的两个基本要素：<strong>分治和聚合</strong>。通过合理地解耦各个组件/层级的功能提高系统的高效性和灵活性，所有组件/层级在完成各自功能的同时组合为完整的软件系统。</p><h3 id="编程语言" tabindex="-1">编程语言 <a class="header-anchor" href="#编程语言" aria-hidden="true">#</a></h3><p>前端架构师在编程语言方面的工作并非集中于语言本身，而是在充分了解语言特性的前提下制定适用于业务类型的开发规范和技术栈。</p><h3 id="技术规范" tabindex="-1">技术规范 <a class="header-anchor" href="#技术规范" aria-hidden="true">#</a></h3><p>包括编码规范、项目源码的组织结构、依赖管理、第三方技术选型。唯一原则是一致性。</p><p>Code Review的目的：</p><ol><li>发现代码逻辑的缺陷以及算法对性能的不良影响；</li><li>纠正开发者不规范的编码方式。</li></ol><h3 id="组件化" tabindex="-1">组件化 <a class="header-anchor" href="#组件化" aria-hidden="true">#</a></h3><p>融入了面向对象的理念，要考虑封装性、扩展性、可组合性、可复用性等。</p><p>按照与产品逻辑耦合程度的强弱，可分为基础组件和业务组件。</p><h3 id="前后端分离" tabindex="-1">前后端分离 <a class="header-anchor" href="#前后端分离" aria-hidden="true">#</a></h3><p>宗旨是将前端开发与后端开发解耦，实现开发、维护、部署、发布的相对独立性。方案分两类：SPA架构和Node.js渲染层。</p><h3 id="性能" tabindex="-1">性能 <a class="header-anchor" href="#性能" aria-hidden="true">#</a></h3><ul><li>加载性能，主要目标是尽可能快地将网站呈现给用户</li><li>执行性能，主要目标是快速响应用户的操作</li></ul><p>前端架构师要在深刻理解浏览器渲染原理、编程语言特性、HTTP等知识的前提下制定适用于前端并且与Web整体架构相契合的性能优化策略。</p><h2 id="工程服务体系" tabindex="-1">工程服务体系 <a class="header-anchor" href="#工程服务体系" aria-hidden="true">#</a></h2><p>前端工程化最基本的原则是在保证产品功能的前提下尽可能地降低迭代所消耗的成本。成本分为：人力成本和沟通成本。</p><p>前端工程服务体系的目标：</p><ul><li>降低开发本身所消耗的人力成本</li><li>降低跨团队协作消耗的沟通成本</li></ul><h3 id="开发" tabindex="-1">开发 <a class="header-anchor" href="#开发" aria-hidden="true">#</a></h3><ul><li>减少重复性体力劳动</li><li>建立规范的代码版本管理规范</li><li>辅助跨团队并行开发</li></ul><h3 id="构建" tabindex="-1">构建 <a class="header-anchor" href="#构建" aria-hidden="true">#</a></h3><ul><li>编程语言：构建针对编程语言的相关功能可以理解为编译，即将源代码转换为客户端可执行的过程。CSS预编译、特定开发框架编译</li><li>性能优化：压缩混淆、自动生成CSS Sprite、动态模块按需加载</li><li>部署策略：给静态资源URL加入Hash指纹和CDN路径</li><li>开发效率：文档生成、动态构建</li><li>审查评估：规范审查、性能评估</li></ul><h3 id="部署" tabindex="-1">部署 <a class="header-anchor" href="#部署" aria-hidden="true">#</a></h3><p>部署最核心的地方并不是对不同类型资源的处理而是对流程的控制</p><h3 id="持续化" tabindex="-1">持续化 <a class="header-anchor" href="#持续化" aria-hidden="true">#</a></h3><p>工程化的第一步是合理地使用工具以提高各个环节独立的工作效率；第二步是搭建自动化流程来提高跨团队协作开发的效率，降低迭代整体所消耗的时间成本；最终的目的是持续化。</p><h3 id="监控和统计" tabindex="-1">监控和统计 <a class="header-anchor" href="#监控和统计" aria-hidden="true">#</a></h3><p>对前端稳定性的监控一方面针对的是前端本身的交互逻辑，但更多针对的是数据接口，也就是服务端的稳定性。在前端调用接口没有返回预期结果时立即反馈到监控平台并且报告错误信息，便于第一时间定位到问题症结。</p>',53),d=[h];function t(n,c,s,o,u,p){return i(),a("div",null,d)}const g=e(r,[["render",t]]);export{_ as __pageData,g as default};
